const baseUrl = $env.PUBLIC_BASE_URL || 'https://your-project.vercel.app';
const apiKey = $env.INVITATION_API_KEY || '';
function normalizePhone(input) {
  let value = String(input || '').trim().replace(/[^\d]/g, '');
  if (value.startsWith('00')) value = value.slice(2);
  if (value.startsWith('0')) value = value.slice(1);
  if (value.length === 9 && value.startsWith('7')) value = `967${value}`;
  return value;
}
return items.map(item => {
  const j = item.json;
  const phone = normalizePhone(j.phone);
  const params = new URLSearchParams({
    name: j.guest_name,
    title: j.title || '',
    phone,
    groomName: 'عبدالله بن محمد',
    familyName: 'عائلتا المثال',
    eventDate: 'مساء الجمعة 15 / 8 / 2026',
    eventTime: '8:30 مساءً',
    venue: 'قاعة المثال للاحتفالات'
  });
  if (apiKey) params.set('apiKey', apiKey);
  const imageUrl = `${baseUrl}/api/invitation-image?${params.toString()}`;
  const displayName = `${j.title || ''} / ${j.guest_name}`.replace(/^ \/ /, '');
  const message = `السلام عليكم ورحمة الله وبركاته\nيشرفنا دعوتكم لحضور حفل الزواج.\nالمدعو الكريم: ${displayName}\nبطاقة الدعوة: ${imageUrl}\nحضوركم يسعدنا ويشرفنا.`;
  return { json: { ...j, phone_e164: phone, display_name: displayName, image_url: imageUrl, whatsapp_click_link: `https://wa.me/${phone}?text=${encodeURIComponent(message)}` } };
});
